#!/usr/bin/env bash
# deal-inbound-close-deal.sh — 一个 deal 从 inbound 到 close 的完整路径(三尺度之「一个 deal」) SOP walkthrough for 风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金)"
WORKFLOW="一个 deal 从 inbound 到 close 的完整路径(三尺度之「一个 deal」)"

usage() {
  cat <<EOF
deal-inbound-close-deal.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./deal-inbound-close-deal.sh             # interactive
  ./deal-inbound-close-deal.sh --dry-run
  ./deal-inbound-close-deal.sh --json
  ./deal-inbound-close-deal.sh --explain
  ./deal-inbound-close-deal.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "一个 deal 从 inbound 到 close 的完整路径(三尺度之「一个 deal」)" 工作流。

一句话: 把一家公司从「pipeline 里的一行」推到「钱打进对方账户、股权进 cap table」—— sourcing → first meeting → 尽调 → IC / partner 决策 → term sheet → 谈判 → close 的完整闭环。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • Power-law 是世界观，不是事后观察到的结果 — 错过比投错致命: VC 的整门生意建立在「一支基金 80%+（业内估计，幂律分布的概数）回报来自 1-2 个 outlier、其余多数 deal 回本或归零」之上；因此判断一个 deal 的第一性问题不是「它稳不稳 /
  • 市场 / 赛道决定论 — 但「市场 vs 团队谁第一」是本行未决的派系张力: 这一行有一条强力镜片——「好团队遇上烂市场，市场赢；烂团队遇上好市场，市场赢」，市场天花板能不能容下一个 return-the-fund 的 outlier 是早期判断的硬约束；但与之并存的是另一极—

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Sourcing + 初筛**:deal 进来,30 秒做背景核查(谁投过 / 上一轮估值 / 创始人是谁),判断是否值得花一次 first meeting。"
  "**First meeting**:30-60 分钟见创始人,听 pitch,问 team / market / product / traction 四块,会后当天写 gut read + 决定 pass / 二次会 / 进尽调。"
  "**尽调(diligence)**:进尽调的 deal 做系统核查 —— founder reference call、产品试用 / demo、market sizing(TAM)、竞争格局、unit economics、cap table review、必要时法律。(详见 W5)"
  "**写投资 memo + IC / partner meeting**:把尽调结论写成结构化 memo(market / team / product / deal terms / risks / 为什么投),拿到投委会 / partner meeting 论证,拿 go / no-go。"
  "**出 term sheet + 谈判**:IC 通过后给 term sheet(估值 + 轮次结构 + 关键条款),与创始人 / 其他投资人谈判到双方签字。(详见 W6)"
  "**法律文件 + close**:term sheet 签了之后律师起草最终文件(股权购买协议 / SAFE / 股东协议),双方签署,资金到账,股权进 cap table。"
)
declare -a FAILURE_MODES=(
  "**太晚暴露给合伙人**:个人偷偷推 deal 到很晚才进 partner meeting,IC 阶段被否,白白浪费自己和 founder 数周 —— 「deal 一进尽调就在 partner meeting 上 floor 一次,早拿到合伙人的方向性反对,而不是把否决留到最后」。"
  "**跳过独立 reference call**:只打创始人给的「友好 reference」 —— 「每个 deal 至少做 2-3 个 off-list(创始人没列)的独立背调,绕开 friendly reference 才能查出 co-founder 矛盾 / 人品问题」。"
  "**口头承诺当成交**:以为创始人「答应了」就稳了,没有 signed term sheet 就停止竞争动作 —— 「在拿到对方签字的 term sheet 之前,deal 一律视为没成,继续保持紧迫感」。"
  "**孤立看单个 deal**:不算这个 deal 在 portfolio 里的 ownership target / reserve 占位,投完才发现 check size 和组合不匹配 —— 「出 term sheet 前先回 W8 对一遍组合,确认这一笔的 check size + reserve 留法」。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "deal-inbound-close-deal-walkthrough"
fi
